var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 퇴원한다고 들었네. 몸은 괜찮나?","JPN":"今日退院すると聞いたが。調子はどうかね？","ENG":"I heard you're being discharged today. How are you feeling?","TWN":"聽說你今天出院了。怎麼樣，還好嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"물론이죠. 다른 분들이 대신 바쁜 덕에 편히 쉰 걸요.","JPN":"おかげさまで。他の方々が代わりによく動いてくださって、ゆっくり休めました。","ENG":"Sure. I got to rest comfortably because others were busy instead.","TWN":"嗯嗯，多虧了別人幫我頂著，我才能這麼悠閒地休息。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"소대원들은 좀 더 회복이 필요할 것 같아서, 저 먼저 복귀하기로 했습니다.","JPN":"他の小隊員はもう少し回復してからということなので、私だけでも先に復帰することにしました。","ENG":"Since other squad members needed more time to recover, I decided to return to work first.","TWN":"因為其他小隊成員還需要更多時間恢復，所以我決定先歸隊了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"필요하면 연차라도 써서 쉬게나. 부사장도 연말 휴가는 못 막을 테니.","JPN":"必要だと思ったら年休でも使いたまえ。さすがの副社長も許可せざるを得ないだろう。","ENG":"If necessary, feel free to use your year-end vacation. Even the Vice President won't object to that.","TWN":"如果覺得太累，可以在年底休假。副總不會拒絕的。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후후, 그렇게 걱정해주시니 마음만으로도 감사하네요.","JPN":"ふふ、そうやって心配してもらえるなんて、心だけでもありがたいですね。","ENG":"Haha, thank you for caring.","TWN":"呵呵，謝謝你的關心。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇지만 귀한 <color=#ffd34c>청춘</color>을 병원에서 낭비하는 건 아깝잖아요? 놀 시간에 경력이라도 쌓아야죠.","JPN":"ですが、貴重な<color=#ffd34c>青春</color>を病院で無駄遣いするのはもったいないでしょう？　遊ぶ時間があるなら経歴を積んでおかないと。","ENG":"But isn't it a bit of a waste to spend my precious <color=#ffd34c>youth</color> in a hospital? I want to build my career, even just a little more.","TWN":"但是把寶貴的[青春]都花在醫院裡有點可惜吧？我想多積累一些職業經驗。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"경력이라…….","JPN":"経歴か……","ENG":"You say career…","TWN":"……原來如此。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 내 생각에 당분간 커리어가 될 만한 일거리는 없을 것 같군.","JPN":"すまないが、しばらく経歴に役立ちそうな仕事は予定にないのでね。","ENG":"But I don't think there will be any tasks that could boost your career for now.","TWN":"很抱歉，暫時沒有能積累經驗的工作了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대신 괜찮다면 신참 카운터 한 명의 교육을 자네에게 맡기고 싶은데.","JPN":"代わりと言ってはなんだか、君には1人の新人カウンターの教育を任せたい。","ENG":"Instead, I'd like to assign you the task of training a rookie Counter if you're okay.","TWN":"但我打算把一個新手制裁者的培訓任務交給你。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네? 제가 신입 교육을요?","JPN":"はい？　私が教育を、ですか？　新人の？","ENG":"Huh? Training a rookie? Me? ","TWN":"嗯？我來嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 정식 사원은 아니지만, 한 사람 몫을 해낼 수 있도록 부탁하지.","JPN":"まだ正社員ではないのだが、一人前のカウンターになれるように指導を頼む。","ENG":"She's not officially an employee yet, but I'm counting on you to help her become competent.","TWN":"雖然還不是正式員工，但希望她能勝任一個人的工作。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"특히 사회생활 쪽으로 말이야.","JPN":"特に社会生活の面で。","ENG":"Especially in terms of social skills.","TWN":"特別是在社會生活這方面。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 개인적인 부탁이니, 부담스럽다면 미리 말하게.","JPN":"私からの個人的な頼みでね。負担になるようなら先に言ってくれ。","ENG":"It's a personal favor of mine. If teaching feels too burdensome, let me know in advance.","TWN":"這是我個人的請求。如果覺得有壓力，可以告訴我。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아핫, 그러니까 사장님의 개인적인 부탁이란 말씀이시죠?","JPN":"ふふ、社長の個人的な頼み、ということですね？","ENG":"Haha, so it is a personal favor from Boss…?","TWN":"呵呵，老闆的私人請求啊……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"마침 잘 됐네요. 간만의 복귀인데, 혼자만 어색하진 않겠어요.","JPN":"ちょうどよかったです。久しぶりの復帰で私だけ気まずくなることはなさそうです。","ENG":"This works out well. As I'm reporting back after a long time, it's good not to be awkward alone.","TWN":"也正好。好久沒回來，能有個人陪著就不會那麼尷尬了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네. 서윤 양만 믿지.","JPN":"ありがとう。ではシズカ君を信じて任せることにしよう。","ENG":"Thank you. I'll leave it all in your hands, Seo Yoon.","TWN":"謝謝。那就麻煩你多費心了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"맡겨만 주세요. 늘 그래왔던 대로.","JPN":"お任せください。いつものように。","ENG":"Leave it to me. Just like always.","TWN":"好的，沒問題。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"쓸데없는 소릴 했네. <color=#ffd34c>청춘</color>을 낭비하고 싶지 않다니.","JPN":"余計なことを言っちゃったわね。<color=#ffd34c>青春</color>を無駄遣いしたくないだなんて。","ENG":"That was a pointless thing to say. <color=#ffd34c>Youth</color>, huh?","TWN":"我在胡說八道什麼，什麼[青春]啊。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"청춘답게 살아본 적도 없는데, 왜 그런 표현이 튀어나온 거람?","JPN":"青春っぽいことなんてしたこともないくせに、何であんなこと言っちゃったんだろう？","ENG":"I've never even experienced a time like that, so why did I say something like that?","TWN":"明明沒有經歷過那樣的時代，為什麼會說出那樣的話呢？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"신입 교관이라…","JPN":"教官の仕事か……","ENG":"Instructor for a rookie...","TWN":"教官的角色啊……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"적어도 심심할 걱정은 없겠어.","JPN":"少なくとも退屈はしなそうね。","ENG":"Well, I won't be bored, at least.","TWN":"至少不會無聊了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아직 도착을 안 했다고요?","JPN":"まだ来ていないんですか？","ENG":"She still hasn't arrived yet?","TWN":"還沒到嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네… 시내버스로 온다고 해서 한 시간째 정류장에서 기다리는데, 안 보이네요.","JPN":"はい……市内バスで来ると聞いていたのでバス停でもう1時間も待っていますが、姿が見えません。","ENG":"No... She said she'd come by city bus, but I've been waiting at the stop for an hour and haven't seen her.","TWN":"嗯……說是要坐公車來，我已經在車站等了一個小時了，還沒看到人。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"연락처도 없어서 아무래도 실종 신고를 하는 편이 좋을 것 같아요.","JPN":"連絡先もなくて、困っているんです。警察に通報した方がいいのでしょうか。","ENG":"She doesn't have a contact number. Should we consider filing a missing person report?","TWN":"沒有聯繫方式，而且年紀又小，要報警嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부장님? 공항에서 회사로 오는 버스 노선은 하나라고 하셨죠?","JPN":"空港から会社までのバスは1本だけですよね？　部長。","ENG":"You mentioned there's just one bus route from the airport to the company, right?","TWN":"從機場到公司的公車線路只有一條，對吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};